static uint64_t program_size(const uint8_t *data) {
    if (data == _binary_hello_elf_start)
        return (uint64_t)(_binary_hello_elf_end - _binary_hello_elf_start);
    if (data == _binary_counter_elf_start)
        return (uint64_t)(_binary_counter_elf_end - _binary_counter_elf_start);
    if (data == _binary_fork_test_elf_start)
        return (uint64_t)(_binary_fork_test_elf_end - _binary_fork_test_elf_start);
    if (data == _binary_cow_test_elf_start)
        return (uint64_t)(_binary_cow_test_elf_end - _binary_cow_test_elf_start);
    if (data == _binary_multifork_test_elf_start)
        return (uint64_t)(_binary_multifork_test_elf_end - _binary_multifork_test_elf_start);
    if (data == _binary_pipe_test_elf_start)
        return (uint64_t)(_binary_pipe_test_elf_end - _binary_pipe_test_elf_start);
    if (data == _binary_signal_test_elf_start)
        return (uint64_t)(_binary_signal_test_elf_end - _binary_signal_test_elf_start);
    if (data == _binary_procfs_test_elf_start)
        return (uint64_t)(_binary_procfs_test_elf_end - _binary_procfs_test_elf_start);
    if (data == _binary_echo_elf_start)
        return (uint64_t)(_binary_echo_elf_end - _binary_echo_elf_start);
    if (data == _binary_ls_elf_start)
        return (uint64_t)(_binary_ls_elf_end - _binary_ls_elf_start);
    if (data == _binary_ps_elf_start)
        return (uint64_t)(_binary_ps_elf_end - _binary_ps_elf_start);
    if (data == _binary_mkdir_elf_start)
        return (uint64_t)(_binary_mkdir_elf_end - _binary_mkdir_elf_start);
    if (data == _binary_touch_elf_start)
        return (uint64_t)(_binary_touch_elf_end - _binary_touch_elf_start);
    if (data == _binary_rm_elf_start)
        return (uint64_t)(_binary_rm_elf_end - _binary_rm_elf_start);
    if (data == _binary_net_test_elf_start)
        return (uint64_t)(_binary_net_test_elf_end - _binary_net_test_elf_start);
    if (data == _binary_nc_elf_start)
        return (uint64_t)(_binary_nc_elf_end - _binary_nc_elf_start);
    if (data == _binary_httpd_elf_start)
        return (uint64_t)(_binary_httpd_elf_end - _binary_httpd_elf_start);
    if (data == _binary_ping_elf_start)
        return (uint64_t)(_binary_ping_elf_end - _binary_ping_elf_start);
    return 0;
}

const struct user_program *user_programs_find(const char *name) {
    static struct user_program result;

    for (int i = 0; programs[i].name; i++) {
        if (strcmp(name, programs[i].name) == 0) {
            result.name = programs[i].name;
            result.data = programs[i].data;
            result.size = program_size(programs[i].data);
            return &result;
        }
    }
    return NULL;
}

void user_programs_populate_ramfs(void) {
    for (int i = 0; programs[i].name; i++) {
        ramfs_add_file(programs[i].name, programs[i].data,
                       program_size(programs[i].data));
    }
}
